import { gs, GlideRecord } from '@servicenow/glide';
export function preventDuplicateRequests(current, previous) {
    const employeeName = current.getValue('employee_name');
    const requestType = current.getValue('request_type');
    // Check for existing active requests (not completed or rejected) for the same employee and request type
    const gr = new GlideRecord('x_2177382_employee_lifecycle');
    gr.addQuery('employee_name', employeeName);
    gr.addQuery('request_type', requestType);
    gr.addQuery('status', 'NOT IN', 'completed,rejected');
    gr.addQuery('sys_id', '!=', current.getUniqueValue());
    gr.query();
    if (gr.hasNext()) {
        gs.addErrorMessage('A duplicate ' + requestType + ' request already exists for this employee. Please check existing requests before submitting a new one.');
        current.setAbortAction(true);
    }
}
